class Solution:
    def getMaxRepetitions(self, s1: str, n1: int, s2: str, n2: int) -> int:
        def count(s1, s2):
            count = 0
            i = 0
            for c in s1:
                if c == s2[0]:
                    i += 1
                    if i == len(s2):
                        count += 1
                        i = 0
            return count

        m = n1 // len(s2)
        r = n1 % len(s2)
        return m + count(s1[:r], s2)
